/* ───────── HERO ───────── */
function Hero() {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start start", "end start"] });
  const y = useTransform(scrollYProgress, [0, 1], ["0%", "30%"]);
  const opacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);

  return (
    <section
      ref={ref}
      className="relative w-full min-h-[calc(100vh-6rem)] overflow-hidden flex items-center justify-center"
    >
      {/* Parallax bg */}
      <motion.div
        style={{ y }}
        className="absolute inset-0 bg-cover bg-center"
        id="hero-bg"
      />
      <style jsx>{`
        #hero-bg {
          background-image: url('https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=1920&q=80');
        }
      `}</style>
      <div className="absolute inset-0 bg-gradient-to-b from-[#0D0D0D]/70 via-[#0D0D0D]/50 to-[#0D0D0D]" />

      <motion.div style={{ opacity }} className="relative text-center px-6 sm:px-8 max-w-4xl mx-auto">
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3, duration: 0.8 }}
          className="text-[#C9A96E] text-xs tracking-[0.4em] uppercase mb-8"
        >
          A Culinary Masterpiece
        </motion.p>

        <motion.h1
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5, duration: 0.8 }}
          className="font-serif text-5xl md:text-7xl lg:text-8xl text-[#F5F0EB] mb-8 leading-tight"
        >
          Aurora <span className="gold-gradient-text italic">Dining</span>
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.7, duration: 0.8 }}
          className="text-[#F5F0EB]/60 text-lg md:text-xl font-light max-w-2xl mx-auto mb-14 font-cormorant tracking-wide"
        >
          Where culinary artistry meets timeless elegance — an unforgettable dining experience awaits
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.9, duration: 0.8 }}
          className="flex flex-col sm:flex-row gap-6 justify-center"
        >
          <Link href="/contact">
            <GoldButton>Reserve a Table</GoldButton>
          </Link>
          <Link href="/menu">
            <OutlineButton>View Menu</OutlineButton>
          </Link>
        </motion.div>
      </motion.div>

      {/* Scroll indicator */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1.5 }}
        className="absolute bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-3"
      >
        <span className="text-[#C9A96E]/50 text-[10px] tracking-[0.3em] uppercase">Scroll</span>
        <motion.div
          animate={{ y: [0, 8, 0] }}
          transition={{ repeat: Infinity, duration: 1.5 }}
          className="w-px h-10 bg-gradient-to-b from-[#C9A96E]/50 to-transparent"
        />
      </motion.div>
    </section>
  );
}

